const TT = (moduleId, id, num, name, slug, tags, hookQ, hookI, blocks, rel, gaps, diff, svgStr, vaType) => ({
  trackKey: TRACK_KEY, moduleId, topicId: id, topicNumber: num, name, slug,
  metadata: { estimated_minutes: 50, difficulty: 4, prerequisites: [], tags },
  hook: { question: hookQ, insight: hookI },
  teaching: { blocks, visual_aid: { type: vaType, svg: svgStr, alt_text: `${name} architecture diagram.` } },
  interviewRelevance: rel, commonGaps: { gaps },
  prerequisites: [], estimatedMinutes: 50, difficulty: diff, xpReward: 80, visualizer: null,
});
const C = (section, heading, body) => ({ kind: "concept", section, heading, body });
const K = (section, heading, body) => ({ kind: "code", section, heading, body });
const G = (id, w, r, d) => ({ gap_id: id, what_students_get_wrong: w, remediation: r, detection_pattern: d });

const TOPICS = [
  // ─────────────────────────── A/B TESTING PLATFORM ────────────────────────
  TT("sysd_m11", "sysd_m11_t5", 5, "Design an A/B Testing Platform", "design-ab-testing",
    ["case-study", "experimentation", "assignment", "statistics"],
    "Product teams want to ship a change to 50% of users, leave the other 50% on the old version, and learn which performs better — across hundreds of simultaneous experiments, with every user always seeing a consistent variant, and a trustworthy verdict at the end. How do you build experimentation infrastructure?",
    "An experiment has variants (control/treatment) and a traffic split; users are ASSIGNED to a variant DETERMINISTICALLY by HASHING (user_id + experiment_id) into a bucket — so assignment is consistent/sticky and needs no per-user lookup — then the variant is served (low-latency, often edge/SDK) and EXPOSURE + metric events are LOGGED. An offline ANALYSIS pipeline computes per-variant metrics and STATISTICAL SIGNIFICANCE, with guardrails. Deterministic consistent assignment + metrics/significance analysis are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: define EXPERIMENTS (variants — control/treatment(s) — and a traffic ALLOCATION, with optional targeting); ASSIGN each user to a variant; SERVE the assigned variant to the app; TRACK exposure + outcome METRICS per variant; ANALYZE results to determine which variant wins (with statistical confidence). Non-functional: CONSISTENT assignment (a user must see the SAME variant every time / across sessions — flipping variants ruins the experiment and UX), LOW-LATENCY variant lookup (it's on the request path of every page/feature), accurate METRICS (correct attribution of outcomes to variants), and SCALE (hundreds/thousands of concurrent experiments, billions of assignments). Clarify scope: an experimentation/A-B testing platform (closely related to feature flags — same assignment machinery). The defining challenges: (1) DETERMINISTIC, CONSISTENT assignment — every user must be stably bucketed into a variant (sticky across requests/sessions/devices) WITHOUT a slow per-user database lookup on the hot path, which is solved elegantly by HASHING rather than storing assignments; and (2) trustworthy ANALYSIS — correctly logging which users were exposed to which variant and which outcomes they had, then computing per-variant metrics and STATISTICAL SIGNIFICANCE (is the difference real or noise?) without statistical pitfalls. So the design centers on consistent deterministic assignment (low-latency, sticky) + a metrics-logging-and-statistical-analysis pipeline."),
      K("estimation", "Capacity estimation (with numbers)",
        "Experiments: hundreds-thousands concurrent ; users: billions of assignments/day.\nAssignment: must be O(1), no DB lookup -> hash(user_id + experiment_id) -> bucket -> variant.\n  deterministic -> same user always same variant (sticky), computed anywhere (edge/SDK).\nServing: variant lookup on every request -> must be sub-ms (config cached locally).\nLogging: exposure events + metric events -> a big event pipeline (like analytics).\nAnalysis: aggregate metrics per variant + statistical significance tests (offline/batch).\nTakeaway: deterministic hash assignment (sticky, lookup-free) on the hot path + an\nevent-logging + statistical-analysis pipeline offline."),
      C("hld", "High-level design",
        "An EXPERIMENT CONFIG (variants, traffic %, targeting rules, layers) is defined and distributed to the serving layer (SDKs in apps / an edge service), cached locally so lookups are fast. ASSIGNMENT: when a user hits a feature, the SDK computes their variant DETERMINISTICALLY — HASH(user_id + experiment_id) -> a number in [0,1) (or a bucket 0–9999) -> map to a variant by the traffic allocation (e.g. <0.5 -> control, else treatment). Because it's a pure hash of stable inputs, the SAME user always gets the SAME variant (STICKY) with NO storage/lookup, and it can be computed anywhere (client, edge, server) consistently. The assigned variant is SERVED, and an EXPOSURE event ('user U saw variant V of experiment E at time T') is LOGGED. The app also logs METRIC/outcome events (clicks, conversions, revenue). An ANALYSIS pipeline (offline/batch + streaming) joins exposures to outcomes, aggregates METRICS PER VARIANT, and runs STATISTICAL SIGNIFICANCE tests to decide if a variant's effect is real, plus GUARDRAIL metrics (don't harm key metrics). Targeting/eligibility (only some users in an experiment) and mutually-exclusive experiment LAYERS prevent interference. Trace it: user -> SDK hashes (U+E) -> variant control -> serve + log exposure -> user converts -> log event -> analysis attributes the conversion to control -> compares variants with significance. Deterministic hash assignment (sticky, lookup-free) + serve + exposure/metric logging + statistical analysis is the shape."),
      K("api", "API / flow",
        "config: experiment { variants, allocation %, targeting, layer } -> distributed to SDKs/edge (cached)\nassign: variant = bucket( hash(user_id + experiment_id) ) mapped by allocation   // deterministic, sticky\nserve: return variant ; LOG exposure { user, experiment, variant, ts }\nmetrics: app logs outcome events (click/convert/revenue)\nanalyze (offline): join exposures + outcomes -> per-variant metrics + significance test + guardrails\ndecision: ship winner / iterate"),
      K("data_model", "Data model",
        "experiments: id, variants, allocation, targeting, layer, status\nassignment: NOT stored per-user -> derived by hash(user_id + experiment_id) (sticky, lookup-free)\nexposure log: (user, experiment, variant, ts) -> who saw what\nmetric events: outcomes (click/convert/revenue) per user\nanalysis results: per-variant metric aggregates + significance / confidence intervals"),
      C("deep_dive", "Deep dive: deterministic, consistent assignment",
        "The elegant core is bucketing users into variants CONSISTENTLY without storing assignments. The naive approach — randomly assign on first visit and STORE the assignment per user — works but requires a database lookup on every request (slow, doesn't scale to billions x hundreds of experiments) and is awkward across devices/edge. The standard solution is DETERMINISTIC HASHING: compute variant = f(HASH(user_id + experiment_id)) — hash the (stable) user identifier combined with the experiment id to a uniform value in [0,1) (or a bucket 0–9999), then map that value to a variant by the traffic allocation (e.g. [0,0.5) -> A, [0.5,1) -> B). Properties this gives 'for free': (1) DETERMINISTIC/STICKY — the same user + experiment always hashes to the same bucket -> same variant every time, across sessions and devices, with NO stored state; (2) NO LOOKUP — it's a pure computation, so it runs in microseconds anywhere (client SDK, edge, server) and scales infinitely; (3) UNIFORM split — a good hash spreads users evenly, so 50% really get A; (4) INDEPENDENT per experiment — including the experiment_id in the hash means a user's bucket in experiment X is uncorrelated with experiment Y (avoiding systematic bias where the same users always land in 'treatment'). MUTUAL EXCLUSION / LAYERS: experiments that could interfere (two changes to the same button) are placed in the SAME 'layer' and partition the traffic so a user is in at most one — implemented by hashing into layer space; independent experiments live in different layers and overlap freely (a user can be in many). TARGETING/eligibility filters who's even in an experiment (then hash among the eligible). SAMPLE RATIO MISMATCH is a key validity check — if the observed split deviates from the configured allocation, something's wrong (a bug). Deterministic hash-based sticky assignment (lookup-free, uniform, independent, layered) is the centerpiece interviewers probe (and why 'store each user's assignment' is the wrong instinct)."),
      C("deep_dive", "Deep dive: metrics, significance & trustworthy analysis",
        "The other half is turning logged events into a TRUSTWORTHY verdict. EXPOSURE LOGGING: when a user is assigned/sees a variant, log an EXPOSURE event (user, experiment, variant, timestamp) — this is the ground truth of who was in which group (and crucially, log exposure at the point of actually experiencing the variant, to avoid counting users who never reached the feature). METRIC EVENTS: the app logs OUTCOMES (clicks, conversions, revenue, retention) per user (the same analytics event pipeline as other products). ANALYSIS PIPELINE: join exposures to outcomes per user, aggregate METRICS PER VARIANT (conversion rate, average revenue, etc.), and compute the DIFFERENCE between treatment and control. STATISTICAL SIGNIFICANCE: the core question is whether an observed difference is REAL or just NOISE — so run a statistical test (e.g. t-test / z-test for proportions, or sequential/Bayesian methods) to get a p-value / confidence interval, only declaring a winner when the result is significant at the chosen threshold AND the effect is practically meaningful. STATISTICAL PITFALLS the platform must guard against: PEEKING (repeatedly checking and stopping when it looks significant inflates false positives — mitigated by fixed sample sizes or sequential testing methods); MULTIPLE COMPARISONS (testing many metrics/variants increases false positives — corrections); insufficient SAMPLE SIZE / power (need enough users for a detectable effect — power analysis up front); SAMPLE RATIO MISMATCH (a skewed split signals a bug, invalidating results); and NOVELTY/seasonality effects. GUARDRAIL METRICS: alongside the target metric, monitor key health metrics (latency, crashes, revenue) so a 'winning' variant that harms something critical is caught/auto-stopped. So rigorous exposure+outcome logging + per-variant aggregation + significance testing + guardrails + avoiding peeking/SRM/multiple-comparison pitfalls is what makes the platform's conclusions trustworthy — exactly what interviewers probe (the stats correctness, not just the plumbing)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "ASSIGNMENT must be sub-ms on every request -> deterministic hashing (no lookup) + locally-cached config; config distribution must be fast/consistent across the fleet. METRIC VOLUME — billions of exposure/outcome events -> a scalable event/analytics pipeline. ANALYSIS CORRECTNESS — the hard part is statistical validity (peeking, multiple comparisons, sample size, SRM) not compute. INTERFERENCE between experiments -> layers/mutual exclusion. CONSISTENCY — a user must never flip variants (sticky hashing guarantees it); changing allocation mid-experiment can reshuffle (handle carefully). DELAYED metrics (retention measured over weeks) -> long-running analysis. Trade-offs: hash assignment (sticky, lookup-free, uniform, scalable — can't easily reassign a specific user) vs stored assignment (flexible, auditable — lookup cost + storage at scale); SDK/edge assignment (fast, offline-capable, consistent — config-distribution lag) vs central-service assignment (simple control, a hot dependency + latency); fixed-horizon significance (rigorous — must wait for the sample) vs sequential/Bayesian (peek-safe, faster decisions — more complex); guardrails + SRM checks (trustworthy — extra monitoring) vs naive 'whichever is higher' (fast, often wrong). Closing signal: deterministic hash-based sticky assignment (hash(user+experiment) -> bucket -> variant, lookup-free, layered for mutual exclusion) served from cached config, with exposure + outcome logging into an analytics pipeline that computes per-variant metrics + statistical significance with guardrails and pitfall-avoidance (peeking/SRM/multiple-comparisons) — consistent assignment at scale + trustworthy verdicts."),
      C("deep_dive", "Deep dive: feature flags, rollouts & operations",
        "Operationally an experimentation platform shares machinery with feature flags and powers safe rollouts. Relation to feature flags: the same deterministic-hash assignment + config-distribution system underpins FEATURE FLAGS (toggle/percentage rollouts) and A/B tests — a flag is a 1-variant rollout, an experiment adds variants + measurement; many platforms unify them. Gradual rollouts & kill switch: ramp a treatment from 1% -> 5% -> 50% -> 100% (the hash lets you grow the bucket), with a KILL SWITCH to instantly disable a bad variant (config push) — experiments double as safe-deploy controls. Config distribution: experiment/flag configs are pushed to all SDKs/edge nodes quickly and consistently (a config service with caching + fast propagation) so assignment behavior is uniform; stale config = inconsistent assignment. SDKs: client + server SDKs evaluate assignment locally (offline-capable) and emit exposure events; they must be lightweight and fail-safe (default to control on error). Holdouts: keep a global HOLDOUT group excluded from all experiments to measure cumulative impact over time. Targeting & segmentation: target experiments to user segments (country, platform, cohort) and analyze results by segment (heterogeneous effects). Metrics platform: a metrics definition layer (consistent metric definitions reused across experiments — like a feature store for metrics) + the analytics pipeline; results dashboards with confidence intervals. Pitfalls automation: the platform should auto-detect SRM, auto-compute required sample size/power, and warn against peeking. Governance: experiment review, naming, lifecycle (draft -> running -> concluded -> archived), and preventing conflicting experiments. Observability: assignment latency, config propagation lag, exposure-logging completeness, SRM alerts, and analysis freshness are the SLOs. The spine holds: deterministic hash assignment from fast-distributed cached config (shared with feature flags), exposure+outcome logging, statistical analysis with guardrails/pitfall-checks, layered for mutual exclusion, with rollouts/holdouts/segmentation."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you assign users consistently without a per-user lookup?' deterministic HASHING — variant = bucket(hash(user_id + experiment_id)) mapped by the traffic allocation; same user always gets the same variant (sticky), computed anywhere, no storage. 'Why include the experiment id in the hash?' so a user's bucket is independent across experiments (no systematic bias of the same users always in treatment). 'Stop two experiments interfering?' layers / mutual exclusion — put conflicting experiments in one layer that partitions traffic so a user is in at most one. 'Is a result real?' statistical significance testing (p-value/confidence interval) — and guard against PEEKING (sequential/fixed-horizon), multiple comparisons, and insufficient sample size. 'A skewed split?' sample-ratio-mismatch check — signals a bug; invalidate. 'Don't ship something harmful?' guardrail metrics + kill switch. 'Low-latency serving?' SDK/edge evaluation from locally-cached config. 'Relation to feature flags?' same assignment + config-distribution machinery; flags are rollouts, experiments add measurement; supports gradual ramp + kill switch. 'Long-term effects?' holdout groups. Each returns to the spine: deterministic hash sticky assignment from cached config + exposure/outcome logging + statistically-rigorous analysis with guardrails, layered."),
    ],
    "An A/B testing platform tests deterministic, consistent ASSIGNMENT — variant = bucket(hash(user_id + experiment_id)) mapped by allocation, so it's sticky and lookup-free, layered for mutual exclusion, served from fast-distributed cached config — plus a trustworthy ANALYSIS pipeline (exposure + outcome logging, per-variant metrics, statistical significance) that guards against peeking, sample-ratio-mismatch, multiple comparisons, and underpowering, with guardrail metrics. The signal is hash-based sticky assignment + statistically-rigorous analysis, not 'store each user's random assignment and eyeball the numbers'.",
    [
      G("stored_assignment", "Randomly assigning and storing each user's variant in a DB.", "Use deterministic hashing (hash(user_id+experiment_id) → bucket → variant): sticky, lookup-free, uniform, scalable.", "Looks up/stores per-user assignments on the request path; doesn't scale, awkward across edge/devices."),
      G("no_significance", "Declaring a winner from raw numbers without statistical significance.", "Run significance tests (p-value/CI) with enough sample; guard against peeking, multiple comparisons, and SRM.", "Picks 'whichever rate is higher'; no significance, peeks early, ignores sample size."),
      G("experiment_interference", "Running overlapping experiments that interfere, with correlated buckets.", "Include experiment_id in the hash (independent buckets) and use layers/mutual exclusion for conflicting experiments.", "Same hash for all experiments / no layering; experiments confound each other."),
    ],
    0.6, DIAG.abtest, "A/B testing platform architecture"),

  // ─────────────────────────── FRAUD DETECTION ─────────────────────────────
  TT("sysd_m10", "sysd_m10_t8", 8, "Design a Fraud Detection System", "design-fraud-detection",
    ["case-study", "fraud", "ml", "real-time"],
    "Every payment must be judged in milliseconds — approve the legitimate buyer instantly, block the stolen card — while fraudsters constantly evolve new tricks and a wrongly-declined real customer is its own kind of failure. How do you score transactions for fraud in real time, accurately, and keep adapting?",
    "Score each transaction in REAL TIME with RULES + an ML model, fed by a FEATURE STORE (velocity, history, device, behavior) → allow / deny / challenge within the latency budget; run an OFFLINE pipeline for deeper ML, model training, and an investigation queue; confirmed fraud feeds back as LABELS to RETRAIN models (fraud evolves adversarially). Real-time rules+ML scoring + offline analysis/feedback/adaptation are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: evaluate transactions/actions (payments, logins, signups) for FRAUD and act — APPROVE, DECLINE, or CHALLENGE (step-up auth) — in real time; investigate suspected fraud; adapt as fraud patterns change. Non-functional: LOW-LATENCY real-time scoring (the decision is on the payment path — milliseconds), ACCURACY balancing false negatives (missed fraud = financial loss) and FALSE POSITIVES (blocking a legitimate customer = lost sale + bad experience — a real cost, not just an annoyance), SCALE (huge transaction volume), and ADAPTABILITY (fraud is ADVERSARIAL — attackers evolve, so the system must keep learning). Clarify scope: a fraud-detection system (payments/account fraud). The defining challenges: (1) REAL-TIME scoring under a tight latency budget — a fraud decision must be made in milliseconds within the transaction flow, using up-to-date signals, so you need fast feature lookup + fast model scoring; (2) the ACCURACY trade-off — both missing fraud and falsely blocking good customers are costly, so it's a careful precision/recall balance (often with a CHALLENGE option for the uncertain middle, rather than a hard allow/deny); and (3) ADVERSARIAL ADAPTATION — fraudsters continuously change tactics, so models drift and must be retrained on fresh confirmed-fraud LABELS, with offline analysis to find new patterns. It combines real-time ML serving (feature store + model — like recsys serving) with a feedback/retraining loop (like content moderation). So the design centers on real-time rules+ML scoring + an offline analysis/feedback/adaptation loop."),
      K("estimation", "Capacity estimation (with numbers)",
        "Volume: huge (every payment/login) -> high QPS real-time scoring.\nLatency: milliseconds per decision (on the transaction path) -> fast features + fast model.\nFeatures: velocity (txns/hour), history, device/IP reputation, behavior -> from a feature store\n  (precomputed + streaming/real-time features).\nDecisions: allow / deny / CHALLENGE (step-up) -> the uncertain middle.\nAdaptation: confirmed fraud (chargebacks, investigations) -> labels -> retrain (fraud evolves).\nTakeaway: real-time rules + ML scoring (feature store, ms budget) for the decision + an\noffline pipeline (deeper ML, investigation, retraining) for accuracy + adaptation."),
      C("hld", "High-level design",
        "REAL-TIME PATH: each transaction is scored synchronously — a RULES engine (fast deterministic checks: blocklists, hard limits, impossible-travel) plus an ML MODEL that takes FEATURES from a FEATURE STORE (precomputed + real-time features: this card's velocity in the last hour, the user's history, device/IP reputation, amount vs typical, behavioral signals) and outputs a fraud SCORE — combined into a decision within the latency budget: ALLOW (low risk), DENY (high risk), or CHALLENGE/step-up (uncertain — require 2FA/verification, reducing false positives by giving good users a way through). REAL-TIME FEATURES: a streaming pipeline updates fast-changing features (velocity counters, recent behavior) so the model sees current state (a fraud ring's burst is visible immediately). OFFLINE PATH: all transactions + outcomes stream to an analytics store where deeper, heavier ML and analysts run — TRAINING models on historical labeled data, hunting NEW fraud patterns, and an INVESTIGATION QUEUE where flagged/uncertain cases are reviewed (the human-in-the-loop, like moderation). FEEDBACK LOOP: confirmed fraud (chargebacks, investigation outcomes, user reports) becomes LABELS that RETRAIN the models — essential because fraud is adversarial and patterns DRIFT. Trace it: payment -> fetch features (store) + rules + ML score -> allow/deny/challenge in ms; meanwhile logged for offline analysis; a later chargeback -> labeled fraud -> next retraining improves the model. Real-time rules+ML scoring (feature store, ms) + offline ML/investigation + a confirmed-fraud feedback/retrain loop is the shape."),
      K("api", "API / flow",
        "real-time: score(transaction) -> features(feature store) + rules + ML model -> risk score\n   -> ALLOW (low) | DENY (high) | CHALLENGE/step-up (uncertain)  [within ms]\nstreaming features: update velocity/behavior counters in real time (fraud bursts visible)\noffline: all txns + outcomes -> analytics store -> train models, find new patterns,\n   investigation queue (human review of flagged cases)\nfeedback: confirmed fraud (chargebacks/investigations/reports) -> labels -> RETRAIN models"),
      K("data_model", "Data model",
        "transactions: features + score + decision + outcome (later: legit/fraud label)\nfeature store: per-entity features (card/user/device): velocity, history, reputation\n  -> online (low-latency reads) + offline (training), kept in sync\nrules: deterministic checks (blocklists, limits, impossible-travel)\nmodels: trained fraud models (versioned) + thresholds for allow/deny/challenge\ninvestigation/labels: flagged cases + confirmed-fraud labels -> training data"),
      C("deep_dive", "Deep dive: real-time scoring (rules + ML + feature store)",
        "The decision path must be FAST and ACCURATE within milliseconds. RULES + ML combined: a RULES engine handles clear-cut, deterministic cases instantly (known-bad cards/IPs on a blocklist, hard limits, impossible-travel = two countries minutes apart, velocity caps) — cheap, explainable, and catches obvious fraud and known patterns; an ML MODEL handles the nuanced majority, learning subtle fraud signals from many features and outputting a risk SCORE. Combining them (rules as fast guardrails + ML for nuance) is standard. FEATURE STORE — the crux of real-time scoring: the model's accuracy depends on rich FEATURES about the transaction's context — VELOCITY (how many transactions/amount on this card/account in the last minute/hour/day — fraud often comes in bursts), HISTORY (the user's normal behavior/amounts/locations — is this anomalous for THEM?), DEVICE/IP reputation (seen before? associated with fraud?), and behavioral signals — and these must be retrievable in MILLISECONDS, so a FEATURE STORE serves precomputed + real-time features with low latency (the same feature-store pattern as recsys). REAL-TIME / STREAMING FEATURES: critically, velocity and recent-behavior features must reflect the LAST FEW SECONDS (a card being rapidly drained right now), so a streaming pipeline updates these counters in real time — the model sees current state, not stale batch data (a fraud burst is only catchable if features are fresh). DECISION with a CHALLENGE option: rather than a binary allow/deny, map the score to ALLOW (low risk — don't annoy good users), DENY (high risk), or CHALLENGE/step-up (the uncertain middle — ask for 2FA/verification) — this CHALLENGE band is key to managing the false-positive cost (a legit user passes the challenge; a fraudster can't), letting you be safe without blocking good customers outright. Fast rules + ML scoring over fresh features (online + streaming feature store) with an allow/deny/challenge decision is the real-time core interviewers probe."),
      C("deep_dive", "Deep dive: offline analysis, feedback & adaptation",
        "Because fraud is ADVERSARIAL and evolving, the system can't be static — the OFFLINE plane provides accuracy and ADAPTATION. OFFLINE ANALYSIS: every transaction + decision + eventual outcome is logged to an analytics/data store where heavier computation runs without the millisecond constraint — TRAINING richer ML models on large historical LABELED datasets, mining for NEW/emerging fraud PATTERNS (e.g. graph analysis to find fraud rings — connected accounts/devices), and computing complex features. INVESTIGATION (human-in-the-loop): flagged or uncertain cases go to an INVESTIGATION QUEUE where analysts review them (the moderation pattern) — confirming or clearing fraud; their decisions both act and generate labels. FEEDBACK LOOP / LABELS: the system learns from OUTCOMES — confirmed fraud arrives via CHARGEBACKS (often days later), investigation conclusions, and user reports — these become LABELED examples that RETRAIN the models, so the system continuously improves and tracks new tactics. This loop is essential because fraud patterns DRIFT (attackers adapt to evade current models — adversarial), so a model that's accurate today degrades; frequent retraining on fresh labels + monitoring for model DRIFT keeps it effective. LABEL DELAY is a real challenge — the true label (fraud or not) may only be known weeks later (chargebacks), so the system uses proxy signals + handles delayed labels in training. THRESHOLD TUNING: the allow/deny/challenge thresholds are tuned against the precision/recall (false-positive vs false-negative) trade-off and business cost, and adjusted as fraud and tolerance change. EXPLAINABILITY: decisions (especially declines) often need reasons (regulatory, disputes), so models/rules provide explanations. So an offline training/analysis pipeline + human investigation + a confirmed-fraud feedback/retraining loop (handling label delay + drift) is what keeps the real-time scorer accurate against an adaptive adversary — exactly what interviewers probe (the adaptation, not just a static model)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "LATENCY vs ACCURACY — the real-time decision is on the payment path (ms), limiting model complexity + feature fetch -> fast feature store + efficient models (heavy ML offline); rules give instant clear-cut decisions. FALSE POSITIVES are a major cost (blocking real customers) -> the CHALLENGE band + threshold tuning + good features reduce them. ADVERSARIAL DRIFT — fraud evolves, models decay -> continuous retraining on fresh labels + drift monitoring. LABEL DELAY — true labels (chargebacks) arrive weeks later -> proxy labels + delayed-label handling. FEATURE FRESHNESS — velocity features must be real-time -> streaming feature pipeline. SCALE — every transaction scored -> high-QPS serving. Trade-offs: rules (fast, explainable, brittle to new fraud) vs ML (catches nuance/novel, opaque, needs labels) -> use both; allow/deny binary (simple, more false positives/negatives) vs add CHALLENGE (manages the uncertain middle, extra friction/flow); real-time features (catch live bursts, streaming complexity/cost) vs batch features (cheap, stale — miss bursts); aggressive blocking (less fraud, more false positives/lost sales) vs lenient (fewer false positives, more fraud) — tuned by cost; frequent retraining (adapts, ops cost) vs static (cheap, decays against adversaries). Closing signal: real-time rules + ML scoring over fresh (online + streaming) features from a feature store, producing allow/deny/CHALLENGE within the latency budget, backed by an offline pipeline (heavier ML, fraud-ring/pattern analysis, human investigation) and a confirmed-fraud feedback loop that retrains models to track evolving, adversarial fraud — balancing missed fraud against false positives."),
      C("deep_dive", "Deep dive: graph analysis, explainability & operations",
        "Operationally fraud detection is a continuously-adapting ML system with real money and customers at stake. Graph / network analysis: much fraud is organized (rings sharing devices, cards, addresses, or coordinated accounts), so a GRAPH view (entities + their connections) reveals rings invisible to per-transaction scoring — offline graph analysis (and sometimes real-time graph features) flags linked-fraud (the graph-DB design). Explainability & compliance: declines/holds often require REASONS (regulatory, customer disputes, fair-lending), so models/rules emit explanations (reason codes, feature attributions); auditability of decisions is required. Case management: the investigation queue is a workflow (prioritize by risk/amount, assign to analysts, track resolution) feeding labels back. Real-time + near-real-time tiers: an instant decision on the transaction (rules + light ML), plus asynchronous deeper checks that can retroactively flag/hold (some fraud is caught seconds-to-minutes later). Feedback integration: chargebacks, manual reviews, user reports, and 3rd-party signals all flow in as labels; handle their delay and noise. Model governance / MLOps: versioned models, shadow/champion-challenger deployment (test a new model in parallel before switching), monitoring for drift and performance, and safe rollback (the model-registry design). Adaptive thresholds + cost modeling: thresholds set by the business cost of each error type; periodically re-optimized. Privacy/security: sensitive data handling; the system itself is a target. Cross-domain signals: device fingerprinting, IP intelligence, behavioral biometrics. Observability: scoring latency, fraud catch rate (recall), false-positive rate, challenge pass rate, model drift, and label-feedback lag are the SLOs. The spine holds: real-time rules+ML over a fresh feature store -> allow/deny/challenge, offline heavier ML + graph/ring analysis + human investigation, and a confirmed-fraud feedback/retrain loop with governance and explainability."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you decide in milliseconds?' rules (fast clear-cut checks) + an ML model scoring features fetched from a low-latency FEATURE STORE -> allow/deny/challenge within the budget. 'What features matter?' velocity (txns/amount per card/account recently), user history/anomaly, device/IP reputation, amount vs typical, behavior — and velocity/behavior must be REAL-TIME (streaming) to catch live bursts. 'Reduce false positives (blocking good customers)?' a CHALLENGE/step-up band for the uncertain middle (2FA) + threshold tuning + better features — both errors are costly. 'Fraud keeps evolving?' it's adversarial — log outcomes, run offline ML + pattern/fraud-ring (graph) analysis, and RETRAIN on confirmed-fraud LABELS continuously; monitor drift. 'Labels arrive late (chargebacks)?' handle label delay (proxy signals, delayed-label training). 'Rules or ML?' both — rules for fast explainable clear cases, ML for nuance/novel patterns. 'Catch organized fraud?' graph analysis of linked entities (shared devices/cards). 'Declines need reasons?' explainability/reason codes (regulatory). 'Deploy new models safely?' champion-challenger/shadow + drift monitoring. Each returns to the spine: real-time rules+ML over fresh features -> allow/deny/challenge, offline ML + investigation, confirmed-fraud feedback retraining."),
    ],
    "A fraud detection system tests real-time RULES + ML scoring over a low-latency FEATURE STORE (velocity, history, device/IP reputation — with STREAMING features to catch live bursts) producing ALLOW/DENY/CHALLENGE within the latency budget (the challenge band manages false positives), backed by an OFFLINE pipeline (heavier ML, fraud-ring/graph analysis, human investigation) and a confirmed-fraud FEEDBACK loop that RETRAINS models against evolving adversarial fraud (handling label delay/drift). The signal is real-time scoring + feedback/adaptation + the false-positive trade-off, not a one-off static classifier.",
    [
      G("static_model", "A static model with no feedback/retraining loop.", "Fraud is adversarial/drifts — log outcomes, retrain on confirmed-fraud labels continuously, monitor drift, run offline pattern analysis.", "Trains once; no labels-back/retraining; degrades as fraud evolves."),
      G("ignore_false_positives", "Optimizing only to catch fraud (binary block), ignoring false positives.", "Balance precision/recall; add a CHALLENGE/step-up band for the uncertain middle + tune thresholds by business cost.", "Hard allow/deny only; blocks many legitimate customers (costly)."),
      G("stale_features", "Scoring on batch/stale features only.", "Serve fresh features from a feature store with real-time/streaming velocity+behavior so live fraud bursts are visible.", "Velocity/behavior features are batch-computed; misses in-progress fraud bursts."),
    ],
    0.7, DIAG.fraud, "Fraud detection architecture"),

  // ─────────────────────────── TINDER (MATCHING) ───────────────────────────
  TT("sysd_m11", "sysd_m11_t8", 8, "Design Tinder (Matching)", "design-tinder",
    ["case-study", "matching", "geo", "recommendations"],
    "Show me nearby people I might like, let me swipe through them, and the instant someone I liked also liked me, tell us both it's a match and open a chat. At a scale of billions of swipes a day. How do you recommend profiles by location and detect mutual likes efficiently?",
    "Two pieces: a RECOMMENDATION feed of candidate profiles (filtered by GEO proximity + preferences, then ranked — proximity search + recsys), and SWIPE recording + MATCH detection — store each swipe (massive write volume), and on a LIKE, check whether the other person ALREADY liked you; if so, it's a MUTUAL match → create a match and open chat. Geo candidate recommendation + efficient swipe storage / reciprocal-like match detection are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: show a user a stream of candidate PROFILES (nearby + matching their preferences), let them SWIPE (like/pass), and when two users LIKE each other (mutual) create a MATCH and enable CHAT between them; manage profiles/preferences. Non-functional: relevant GEO-based recommendations (nearby people first), efficient handling of MASSIVE swipe volume (billions of swipes/day — write-heavy), real-time MATCH detection (a mutual like should produce a match immediately), and scale. Clarify scope: the discovery + matching core of a dating app (Tinder-style). It composes two familiar problems: (1) RECOMMENDATION/feed — generate a ranked stream of candidate profiles for a user, primarily filtered by GEOGRAPHIC proximity (nearby) plus preferences (age/gender/distance) and quality/ranking — i.e. PROXIMITY search + a recommendation funnel; and (2) the distinctive MATCHING mechanic — record each swipe (a huge volume of writes), and detect MUTUAL likes: a MATCH occurs precisely when user A liked B AND B liked A, which must be detected efficiently the moment the second like happens. The interesting parts are the geo-filtered recommendation at scale and the efficient detection of reciprocal likes among billions of swipes (you can't scan). So the design centers on geo candidate recommendation + swipe storage + reciprocal-like match detection."),
      K("estimation", "Capacity estimation (with numbers)",
        "Swipes: billions/day -> write-heavy ; most are 'pass' (no match) -> store efficiently.\nRecommendations: per user, a feed of nearby candidates -> geo index + preferences + ranking.\nMatch: a match needs BOTH directions liked -> on each LIKE, check reciprocal (did they like me?).\n  -> O(1) lookup 'does (other -> me) like exist?' (not a scan).\nMatches: relatively rare vs swipes -> matches store + enable chat.\nTakeaway: geo-filtered ranked recommendations + high-volume swipe storage + an efficient\nreciprocal-like check on each like to detect mutual matches."),
      C("hld", "High-level design",
        "RECOMMENDATION: for a user, generate a feed of candidate PROFILES — filter by GEO (people within their distance preference, via a geospatial index — geohash/quadtree, the proximity-search pattern) and PREFERENCES (age/gender/etc.), then RANK the candidates (by attractiveness/activity/compatibility — a recsys-style scoring) and serve a batch the user swipes through; precompute/cache feeds to keep swiping snappy. SWIPE: each swipe (like or pass) is RECORDED (a write to a swipe store) — this is the high-volume write path (billions/day), so it's stored efficiently and may be processed via a stream. MATCH DETECTION: when a user A LIKES B, the system checks whether B has ALREADY liked A — i.e. does a like (B -> A) exist? If yes, it's a MUTUAL match: create a MATCH record for the pair and notify both, enabling CHAT (a separate messaging system). This reciprocal check must be an efficient O(1) lookup ('does like(B,A) exist?'), not a scan. Passes never create matches. Trace it: user opens app -> recommendation feed (nearby + prefs + ranked) -> swipes -> each swipe stored -> on a LIKE of B, check if B liked A -> if yes, create match + notify both -> chat opens. Geo+preference+ranked recommendations + efficient swipe storage + reciprocal-like match detection (+ chat) is the shape."),
      K("api", "API / flow",
        "GET /recommendations -> candidate profiles: geo (within distance) + preferences + ranking\nPOST /swipe { targetId, dir: like|pass } -> store swipe\n   if dir == like: check exists like(target -> me)?  (O(1) lookup)\n      yes -> create MATCH(me, target) + notify both -> enable chat\n      no  -> just stored (await their swipe)\nGET /matches -> matched users ; chat via messaging service\nprofiles/preferences: CRUD ; geo index updated on location change"),
      K("data_model", "Data model",
        "profiles: id, location (lat/lng -> geo index), attributes, preferences\ngeo index: geohash/quadtree of profiles -> nearby candidate lookup\nswipes: (from_user, to_user, dir, ts) -> huge write volume ; indexed for reciprocal lookup\n  key insight: cheaply answer 'does like(B -> A) exist?' on each like\nmatches: (userA, userB, ts) -> enables chat (messaging service)\nrecommendation cache: precomputed candidate feed per user"),
      C("deep_dive", "Deep dive: candidate recommendation (geo + preferences + ranking)",
        "Generating the swipe feed is a PROXIMITY + RECOMMENDATION problem. GEO FILTERING is primary: dating is local, so candidates are first filtered to those within the user's distance preference — using a GEOSPATIAL INDEX (geohash, quadtree, or a geo-capable store) to efficiently find nearby profiles (the proximity-service pattern), rather than scanning everyone. PREFERENCE FILTERING: apply the user's hard filters (age range, gender, max distance) and mutual eligibility (the candidate's preferences must also include this user — bidirectional preference matching). RANKING: among eligible nearby candidates, ORDER them to maximize good matches/engagement — a recsys-style scoring using signals like attractiveness/desirability (historically an ELO-like score), activity/recency (show active users), and compatibility/affinity (shared interests, collaborative signals from swipe patterns) — so the user sees promising profiles first, not random ones. This is the retrieval (geo + filters) -> ranking funnel from the recommendation-system design, scoped to nearby people. FEED GENERATION/CACHING: serving a batch of ranked candidates (and precomputing/caching the feed) keeps swiping instant; as the user swipes through, more are fetched. FRESHNESS/dedup: don't reshow already-swiped profiles (track seen), refresh as the user moves (location changes update the geo index) and as candidates' availability changes. BALANCING exposure: distribute likes/attention (avoid everyone piling onto a few hyper-popular profiles — fairness, and so most users get matches). So geo proximity filtering + preference/eligibility filtering + ranking (desirability/activity/compatibility) + cached feed generation is the recommendation half — combining the proximity and recsys patterns, which is what interviewers expect (not 'just show nearby people randomly')."),
      C("deep_dive", "Deep dive: swipe storage & reciprocal-like match detection",
        "The distinctive engineering is handling the enormous SWIPE volume and detecting MUTUAL likes efficiently. SWIPE STORAGE: billions of swipes/day is a write-heavy firehose; each swipe (from, to, direction) is recorded — most are PASSES that never matter for matching, so store them efficiently (sharded by user, possibly with passes handled more cheaply than likes); a swipe stream can feed analytics/recommendations. The store must be sharded to handle the write volume and indexed to support the match check. MATCH DETECTION (the heart): a MATCH = a RECIPROCAL like (A liked B AND B liked A). The naive 'periodically scan for pairs where both liked' is infeasible at this scale; instead, detect it INCREMENTALLY at swipe time: when A swipes LIKE on B, immediately CHECK whether the reverse like already exists — 'does like(B -> A) exist?' — an O(1)/O(log n) lookup (e.g. look up B's likes for A, or a keyed swipe store on (to_user, from_user)). If it exists, the two have mutually liked -> CREATE a MATCH record (for the pair, often a canonical ordered key to avoid duplicates) and NOTIFY both users in real time, enabling CHAT. If not, the like is just stored, waiting for B to (maybe) like A later — at which point B's like triggers the same reciprocal check (finding A's earlier like) and the match forms. This 'check reciprocal on each like' approach makes match detection instant and cheap (one lookup per like) instead of scanning pairs. CONSISTENCY/idempotency: creating the match must be safe under the two likes possibly racing (both like near-simultaneously) — use a canonical pair key + idempotent match creation so exactly one match is created and both are notified. CHAT: once matched, a separate messaging system (the chat design) handles conversation. Efficient sharded swipe storage + per-like reciprocal-existence check to detect mutual matches instantly (not scanning) is the core interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "SWIPE WRITE VOLUME — billions/day; shard the swipe store by user, store passes cheaply, possibly process via a stream. GEO RECOMMENDATION at scale — geospatial index (geohash/quadtree) + cached feeds; updating as users move. MATCH DETECTION — must be O(1) per like (reciprocal lookup), never a scan; the swipe store keyed to answer 'does like(B,A) exist?'. POPULAR PROFILES — a few users get a huge share of likes (skew) -> their swipe/like data is hot; balance exposure so attention/matches spread (fairness + most users matching). RACE on simultaneous mutual likes -> idempotent match creation (canonical pair key). REAL-TIME match notification -> push (notifications/WebSocket). Trade-offs: check-reciprocal-on-each-like (instant matches, O(1) per like, needs the right index) vs batch-scan-for-pairs (simple, infeasible at scale); store all swipes incl. passes (full data for recs/analytics, huge volume) vs store likes only / passes cheaply (less data, lighter); geo+rank recommendation (relevant, complex funnel) vs nearest-only (simple, lower quality); precomputed feed (fast swiping, can go stale as user moves) vs on-demand (fresh, slower); ranking by desirability (better matches/engagement, fairness concerns) vs random/recency (simple, lower quality). Closing signal: a geo-filtered + preference-filtered + ranked recommendation feed (proximity + recsys, cached) for swiping, high-volume sharded swipe storage, and INSTANT match detection via a reciprocal-like existence check on every like (idempotent match creation + real-time notify -> chat) — recommending nearby relevant profiles at scale and detecting mutual matches without scanning."),
      C("deep_dive", "Deep dive: chat, abuse, fairness & operations",
        "Operationally a dating app is discovery + matching + messaging + heavy trust-and-safety. Chat after match: a match unlocks a conversation handled by a messaging system (the chat/Slack design — real-time delivery, history) — only matched users can message (a privacy/anti-harassment constraint). Profiles & media: profile photos/videos in object storage (+ a media pipeline for processing), profile data + preferences in a store; verification (photo verification) to reduce fakes. Trust & safety: dating apps are abuse-prone — fake profiles/bots/scammers detection, photo/content moderation (the moderation design), blocking/reporting, and safety features; this is a major operational area. Fairness & ecosystem health: ranking and rate-limits balance attention so it isn't monopolized by a few profiles (which would leave most users matchless and churned) — a marketplace-balance concern; some apps limit daily likes. Geo & movement: location updates re-index the user; 'passport'/travel features change the geo center; respect location privacy (coarsen precise location). Recommendations evolution: incorporate swipe feedback (who you like/pass) into ranking (collaborative filtering on preferences) — the recsys feedback loop. Notifications: real-time match + message notifications (push gateway). Scale & sharding: profiles, swipes, and matches sharded by user; geo index distributed; the swipe firehose is the heaviest write path. Monetization features (boosts, super-likes, who-liked-you) layer on the core. Dedup/seen tracking: never reshow swiped profiles. Observability: recommendation latency, swipe write throughput, match-creation latency/correctness, like-distribution skew, and abuse/report rates are the SLOs. The spine holds: geo+preference+ranked recommendations + sharded swipe storage + reciprocal-like match detection + match-gated chat, with strong trust-and-safety and ecosystem-fairness."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you show nearby relevant profiles?' a geospatial index (geohash/quadtree) for proximity + preference/eligibility filtering + ranking (desirability/activity/compatibility) — the proximity + recsys funnel, with a cached feed. 'Detect a match efficiently among billions of swipes?' don't scan — on each LIKE, check if the reciprocal like already exists ('does like(B->A) exist?', an O(1) lookup); if yes, create the match instantly. 'Two people like each other at the same time?' idempotent match creation with a canonical pair key so exactly one match forms and both are notified. 'Handle billions of swipes/day?' shard the swipe store by user, store passes cheaply, stream for analytics. 'Popular profiles get all the likes?' balance exposure / rate-limit likes so attention spreads (most users should get matches — ecosystem health). 'After a match?' a chat system (match-gated messaging) + real-time notification. 'Abuse/fakes?' moderation, verification, blocking/reporting (dating is abuse-prone). 'Improve recommendations?' learn from swipe feedback (collaborative filtering). 'Location privacy?' coarsen precise location. Each returns to the spine: geo+preference+ranked recommendations + sharded swipe storage + per-like reciprocal match detection + match-gated chat, with trust-and-safety + fairness."),
    ],
    "Designing Tinder tests two composed problems: a RECOMMENDATION feed filtered by GEO proximity (geospatial index) + preferences and then ranked (proximity + recsys funnel, cached), and the MATCHING mechanic — high-volume sharded SWIPE storage plus INSTANT match detection by checking, on each like, whether the reciprocal like already exists (O(1) lookup, not a scan), with idempotent match creation + real-time notify → match-gated chat. The signal is geo recommendation + reciprocal-like match detection at scale, not scanning for mutual-like pairs.",
    [
      G("scan_for_matches", "Periodically scanning for pairs where both users liked each other.", "Detect incrementally: on each LIKE, check if the reciprocal like already exists (O(1) lookup) → create the match instantly.", "Batch-scans the swipe data for mutual likes; infeasible at billions of swipes."),
      G("no_geo_index", "Finding nearby candidates by scanning all profiles.", "Use a geospatial index (geohash/quadtree) for proximity, then preference-filter + rank — the proximity + recsys funnel.", "Filters distance by computing it over every profile; no geo index."),
      G("match_race", "Creating matches non-idempotently when both like near-simultaneously.", "Use a canonical pair key + idempotent match creation so exactly one match forms and both are notified.", "Two simultaneous likes create duplicate matches / race conditions."),
    ],
    0.6, DIAG.tinder, "Tinder matching architecture"),

  // ─────────────────────────── COMMENT SYSTEM ──────────────────────────────
  TT("sysd_m11", "sysd_m11_t3", 3, "Design a Comment System", "design-comment-system",
    ["case-study", "hierarchical-data", "read-heavy", "sorting"],
    "An article gets thousands of comments, replies to comments, replies to those replies — and millions of readers load the thread, sorted by 'top' or 'newest', paginated, instantly. Threaded, nested, read-heavy, and at scale. How do you model and serve a comment system?",
    "Model the NESTED/threaded structure — each comment stores a parent reference (a tree), or use a materialized path / closure table for efficient subtree fetch — and serve the READ-HEAVY workload by caching, sorting (top/new, often by vote score), paginating top-level comments and lazy-loading replies, with denormalized counts. Modeling hierarchical threaded comments + read-heavy sorted/paginated serving are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: post COMMENTS on an item (article/post/video), post REPLIES to comments (NESTED/threaded, potentially several levels deep), display the comment thread SORTED (top/best by votes, or newest), with PAGINATION (load more); upvote/downvote; edit/delete; moderation. Non-functional: READ-HEAVY scale (a popular item's comments are read by millions, written by far fewer — read-optimized), efficient retrieval and rendering of the NESTED tree, flexible SORTING, low latency, and handling hot items. Clarify scope: a comment system (Reddit/Disqus/YouTube-comments style). The defining challenges: (1) modeling HIERARCHICAL/THREADED data — comments form a TREE (replies to replies), and you must store and FETCH this nesting efficiently (fetch a comment plus its subtree, paginate within levels) — naive approaches make deep threads slow; and (2) READ-HEAVY serving at scale with SORTING and PAGINATION — comments are read vastly more than written, so caching + read-optimization matter, and threads must be SORTED (by score/time) and PAGINATED (you can't load 10,000 comments at once), which is non-trivial for a tree (paginate top-level, lazy-load replies). So the design centers on the hierarchical data model (how to store/fetch the tree) + read-heavy sorted/paginated serving."),
      K("estimation", "Capacity estimation (with numbers)",
        "Reads >> writes: a hot thread read by millions, commented by thousands -> cache + read-optimize.\nNesting: replies form a tree, possibly deep -> need efficient subtree fetch.\nSorting: top (by vote score) or new -> per-thread ordering ; recompute on votes.\nPagination: thousands of comments -> paginate top-level + lazy-load replies (don't load all).\nCounts: reply counts / vote counts -> denormalized for fast display.\nTakeaway: model the tree for efficient subtree fetch, serve read-heavy with caching +\nsorting (top/new) + pagination (top-level + lazy replies) + denormalized counts."),
      C("hld", "High-level design",
        "STORAGE: comments are stored with their THREAD structure — the simplest model is each comment row holding a PARENT_ID (the comment/post it replies to), forming a tree; for efficient subtree reads, richer models use a MATERIALIZED PATH (store the path from root, e.g. '1/4/9', so a subtree is a prefix query) or a CLOSURE TABLE (ancestor-descendant pairs). Each comment also has the item it belongs to, author, body, timestamp, and vote/reply COUNTS (denormalized for fast display). READ PATH (the hot path): to render a thread, fetch the TOP-LEVEL comments for the item, SORTED (by vote score for 'top'/'best', or timestamp for 'new'), PAGINATED (a page of top-level comments), and for each, fetch a few REPLIES (lazy-load deeper/more replies on demand — 'view more replies') — assembling the nested view; results are heavily CACHED (read-heavy). VOTES update scores (which affect 'top' sorting — like the hot-ranking design). MODERATION (remove/flag) and counts are maintained. WRITES (post comment/reply) insert a comment with its parent, update counts, and invalidate/refresh relevant caches. Trace read: load article -> fetch top-level comments (sorted top, page 1) + first few replies each -> render threaded -> user clicks 'more replies' -> lazy-fetch that subtree. Tree storage (parent ref / materialized path) + read-heavy sorted + paginated (top-level + lazy replies) + cached serving + denormalized counts is the shape."),
      K("api", "API / flow",
        "POST /comments { itemId, parentId?, text } -> insert (with parent) + update counts + invalidate cache\nGET /items/{id}/comments?sort=top|new&cursor -> top-level comments (sorted, paginated)\n   + first N replies each (lazy-load more replies via /comments/{id}/replies?cursor)\nvote: POST /comments/{id}/vote -> update score (affects 'top' sort)\nrender: assemble nested tree from fetched comments + replies\ncache: hot threads cached ; counts (replies/votes) denormalized"),
      K("data_model", "Data model",
        "comments: id, item_id, parent_id (tree), author, body, ts, score, reply_count\n  threading model: parent_id (simple) | materialized path '1/4/9' (subtree = prefix) | closure table\nvotes: (comment, user) -> score (for top sorting) ; denormalized score on comment\ncache: per-item comment pages (sorted) + hot subtrees (read-heavy)\nmoderation: status (visible/removed/flagged)"),
      C("deep_dive", "Deep dive: modeling nested / threaded comments",
        "The first challenge is storing and efficiently FETCHING the comment TREE. The basic model is ADJACENCY LIST: each comment stores a PARENT_ID (null for top-level, else the comment it replies to) — simple to write (just set parent), and natural, but reading a deep subtree requires recursive queries (fetch children, then their children…) which can be many round-trips / a recursive CTE — fine for shallow threads, costly for deep ones. Richer models optimize subtree reads: MATERIALIZED PATH — store each comment's PATH from the root (e.g. '0001/0004/0009'), so fetching an entire subtree is a single PREFIX/range query (WHERE path LIKE '0001/0004/%') and ordering/depth come from the path — fast reads, at the cost of path maintenance (and moves); CLOSURE TABLE — a separate table of all (ancestor, descendant, depth) pairs, so you can query a node's whole subtree or ancestors with a simple join — flexible reads (any subtree/ancestry) at the cost of extra storage (O(n*depth) rows) and write overhead (insert ancestor rows on each comment); NESTED SET — left/right bounds for subtree-as-range (great reads, expensive writes/rebalancing — rarely used for active comments). The choice depends on read/write patterns: comments are read-heavy and append-mostly (replies added, rarely re-parented), so materialized path or adjacency-list-plus-caching are common; closure tables when arbitrary ancestry queries matter. Many real systems also LIMIT NESTING DEPTH (e.g. collapse beyond N levels, like Reddit) to bound the tree and simplify rendering. So modeling the hierarchy (adjacency list vs materialized path vs closure table) for efficient SUBTREE FETCH + pagination — matched to the read-heavy, append-mostly pattern, often with a depth cap — is the data-modeling core interviewers probe (it's why 'just store parent_id and recurse' can be insufficient at scale/depth)."),
      C("deep_dive", "Deep dive: read-heavy serving, sorting & pagination",
        "The second challenge is serving the read-heavy workload with SORTING and PAGINATION over a tree. READ-HEAVY -> CACHE: a popular thread is read by millions, so cache rendered comment pages / subtrees aggressively (and use read replicas); comments change relatively slowly (new replies, votes), so cache with short TTLs or invalidate on write — high hit rates make this cheap. SORTING: threads are shown by 'TOP/BEST' (by vote SCORE — the hot-ranking/leaderboard idea: a score combining votes, sometimes with time decay or a confidence sort like Wilson score) or 'NEW' (by timestamp) or 'controversial', etc. — so the system maintains/queries comments in sorted order PER LEVEL (top-level comments sorted, and replies within a parent sorted); scores update on votes (recompute/maintain a sorted structure). PAGINATION over a tree (the tricky part): you can't load thousands of comments at once, so paginate the TOP-LEVEL comments (a page at a time, by the chosen sort, via a cursor) and for each top-level comment load only the FIRST few replies, with a 'view more replies' that LAZY-LOADS deeper/more of that subtree on demand — so the initial render is bounded and the user expands as needed (this is how Reddit/YouTube render huge threads). DENORMALIZED COUNTS: reply counts and vote counts are denormalized onto comments (updated on write) so the UI shows '142 replies' without counting — fast display. HOT ITEMS / write spikes: a viral thread gets many concurrent comments + votes -> cache reads, and handle the write/vote volume (the comment write path + vote updates, possibly async/batched). So aggressive caching + per-level sorting (by score/time) + tree pagination (paginate top-level, lazy-load replies) + denormalized counts is how a comment system serves massive read traffic over a nested structure — the serving core interviewers probe (it's why naive 'fetch the whole tree and sort' fails for big threads)."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "READ SCALE dominates -> cache (rendered pages/subtrees) + read replicas; comments change slowly so caching is effective. DEEP NESTING / large subtrees -> efficient subtree model (materialized path/closure) + depth caps + lazy-loading replies (don't fetch the whole tree). SORTING large threads -> maintain sorted order per level (by score/time); votes update scores (hot-ranking style); 'top' sort recompute cost. PAGINATION over a tree -> paginate top-level + lazy replies (can't offset into a tree naively) — cursor-based. HOT THREADS / vote storms -> cache + async/batched vote+count updates. WRITE -> insert + count updates + cache invalidation. Trade-offs: adjacency list/parent_id (simple writes, recursive/expensive subtree reads) vs materialized path (fast subtree reads, path maintenance) vs closure table (flexible ancestry queries, storage + write overhead); cache aggressively (fast reads, invalidation/staleness on new replies) vs always-fresh (consistent, hammers DB); sort by score/top (engaging, recompute on votes) vs by new (simple, chronological); paginate top-level + lazy replies (bounded load, more requests) vs load-whole-thread (simple, infeasible for big threads); denormalized counts (fast display, must keep in sync) vs count-on-read (accurate, slow). Closing signal: model the comment TREE for efficient subtree fetch (parent_id / materialized path / closure table, often depth-capped), and serve the read-heavy workload via aggressive caching + per-level sorting (top by score / new by time) + tree pagination (paginate top-level, lazy-load replies) + denormalized counts — threaded comments rendered fast at scale."),
      C("deep_dive", "Deep dive: votes, moderation, real-time & operations",
        "Operationally a comment system is a read-heavy hierarchical store with social features. Voting & ranking: votes drive 'top/best' sorting — store votes (dedup one per user), maintain a denormalized score, and rank by a formula (raw score, time-decayed 'hot', or a confidence/Wilson sort that handles few-votes fairly); vote storms on viral threads need efficient (batched/async) count updates. Moderation: spam/abuse filtering, user reports, remove/flag (the moderation design), shadow-removal, and showing '[removed]' placeholders while preserving tree structure; auto-moderation + human review. Real-time updates: optionally push new comments/votes live (WebSocket) so an open thread updates without refresh (the chat/fan-out pattern) — for live discussions. Collapsing & UX: collapse deep/low-score subtrees, 'continue this thread', and load-more — bounding what's rendered; this drives the pagination/lazy-load design. Edits/deletes: versioned or simple edit with an 'edited' flag; delete preserves tree (tombstone) so replies remain. Counts & aggregates: reply counts, vote counts, and per-item total comment counts denormalized and updated on write (eventually consistent). Caching strategy: cache per-item sorted comment pages + hot subtrees; invalidate/refresh on new comments/votes (or short TTL); CDN for fully-public rendered comments. Scale & sharding: shard comments by item (a thread's comments together) so a thread's reads/writes localize; very hot items get extra caching. Notifications: reply notifications to the parent author (notification system). Search/indexing: optionally index comments for search. Observability: comment-read latency + cache hit rate, write/vote throughput, deep-thread fetch latency, and moderation queue depth are the SLOs. The spine holds: a tree model (parent/path/closure, depth-capped) + cached, per-level-sorted, tree-paginated read serving + denormalized counts, with voting/ranking, moderation, and optional real-time updates, sharded by item."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you model nested replies?' a tree — each comment has a parent_id (adjacency list, simple writes but recursive reads), or a materialized path (subtree = prefix query, fast reads) or closure table (flexible ancestry, more storage/writes); often cap nesting depth. 'Render a thread with thousands of comments?' don't load the whole tree — paginate TOP-LEVEL comments (by sort, cursor) and lazy-load a few replies each, expanding subtrees on demand ('view more replies'). 'Sort?' top/best by vote SCORE (hot-ranking/Wilson), or new by time — maintain sorted order per level; votes update scores. 'Read-heavy scale?' cache rendered pages/subtrees aggressively (comments change slowly) + read replicas; CDN for public. 'Reply counts?' denormalized + updated on write (fast display). 'Hot thread / vote storm?' cache + async/batched vote+count updates; shard comments by item. 'Live updates?' optionally push new comments via WebSocket. 'Deleted comment with replies?' tombstone to preserve the tree. 'Deep subtree fetch?' materialized path/closure for efficient prefix/ancestry queries. Each returns to the spine: tree model (parent/path/closure, depth-capped) + cached per-level-sorted tree-paginated serving + denormalized counts, with voting/moderation, sharded by item."),
    ],
    "A comment system tests modeling HIERARCHICAL/threaded data (a tree via parent_id / materialized path / closure table — chosen for efficient subtree fetch, often depth-capped) and serving a READ-HEAVY workload with aggressive caching, per-level SORTING (top by vote score / new by time), TREE PAGINATION (paginate top-level + lazy-load replies, not the whole tree), and denormalized counts, sharded by item. The signal is the hierarchical model + read-heavy sorted/paginated tree serving, not 'store parent_id and load the whole thread'.",
    [
      G("load_whole_tree", "Fetching and rendering the entire comment tree at once.", "Paginate top-level comments + lazy-load a few replies each (expand subtrees on demand); never load thousands at once.", "Loads all comments for a thread in one query/response; fails for big threads."),
      G("naive_recursion", "Only parent_id with recursive queries for deep subtree reads.", "For read-heavy deep threads use a materialized path (prefix query) or closure table for efficient subtree fetch; cap depth.", "Recurses level-by-level for every subtree read; slow/many round-trips on deep threads."),
      G("no_caching_counts", "Serving every read from the DB and counting replies/votes on read.", "Cache rendered pages/subtrees (comments change slowly) + denormalize reply/vote counts updated on write.", "No caching; counts computed by scanning; read-heavy load hits the DB directly."),
    ],
    0.4, DIAG.comments, "Comment system architecture"),

  // ─────────────────────── LIVE LOCATION SHARING ───────────────────────────
  TT("sysd_m12", "sysd_m12_t7", 7, "Design Live Location Sharing", "design-live-location-sharing",
    ["case-study", "real-time", "geo", "fan-out"],
    "A friend shares their live location with you and a dot glides across your map as they walk home; a delivery app shows the courier approaching in real time. The phone can't ping its GPS every second without dying, and one sharer may have many watchers. How do you stream live location at scale?",
    "The sharer's device sends periodic location UPDATES (THROTTLED to save battery/bandwidth), a service stores the CURRENT location (fast in-memory) and FANS OUT updates in real time to the subscribed VIEWERS (WebSocket/push via pub/sub) — much like presence but with coordinates. Scale comes from throttling update frequency (adaptive) and efficient fan-out to many viewers; a geo store supports nearby use cases. Ingesting + fanning out throttled location updates + scaling efficiently are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: a user SHARES their live location; authorized VIEWERS see it update in (near) REAL TIME on a map (e.g. friends watching you walk home, or tracking a delivery courier/ride); start/stop sharing; show movement/trail. Non-functional: REAL-TIME updates (location refreshes within seconds), efficient FAN-OUT to viewers (one sharer may have many watchers), BATTERY/BANDWIDTH efficiency on the sharer's device (constant high-frequency GPS + uploads drains the phone), SCALE (many concurrent sharers + viewers), and eventual consistency is fine. Clarify scope: live location sharing/tracking (Find My Friends / Uber driver tracking / delivery tracking). It's very close to the PRESENCE design but with continuous COORDINATES instead of a binary online/offline: a device emits frequent updates, and those updates must reach interested viewers in real time. The defining challenges: (1) INGESTING frequent location updates from many devices WITHOUT draining their batteries — so updates are THROTTLED (sent every few seconds, not continuously) and the frequency is often ADAPTIVE (more often when moving fast / being actively watched, less when stationary); and (2) real-time FAN-OUT — a location update must be pushed to all current VIEWERS of that sharer quickly, which at scale (popular shares, or a courier watched by a customer + dispatch) is a fan-out problem (like presence/chat). So the design centers on throttled location ingestion + real-time fan-out to viewers, done efficiently."),
      K("estimation", "Capacity estimation (with numbers)",
        "Updates: sharers send location every ~3-10s (throttled) -> high steady ingest, but bounded.\n  continuous GPS+upload would drain battery -> throttle + adaptive frequency.\nCurrent location: per sharer -> store latest in-memory (Redis) ; small (lat/lng + ts).\nFan-out: each update -> all current VIEWERS of that sharer (often few; sometimes many).\nReal-time: push to viewers via WebSocket / push (pub/sub), within seconds.\nTakeaway: throttled (adaptive) location ingest + a current-location store + real-time fan-out\nto subscribed viewers -> like presence with coordinates."),
      C("hld", "High-level design",
        "INGEST: the sharer's device sends periodic LOCATION UPDATES (lat/lng + timestamp) over a connection (WebSocket or lightweight HTTP/MQTT), THROTTLED to every few seconds (and often ADAPTIVE — faster when moving/being watched, slower when still/unwatched) to conserve battery/bandwidth. A LOCATION SERVICE receives updates and stores the CURRENT location per sharer in a fast IN-MEMORY store (Redis) — only the latest matters for live view (history optional). FAN-OUT: each update is pushed in REAL TIME to the current VIEWERS subscribed to that sharer — via a pub/sub layer to the gateway servers holding viewers' connections (WebSocket), who push the new coordinates to clients (so the dot moves on their map). Viewers SUBSCRIBE when they open the share and unsubscribe when they leave (so you only fan out to active viewers). For NEARBY/discovery use cases (who's around), a geospatial index supports geo queries. The pattern mirrors PRESENCE (connections, subscriptions, pub/sub fan-out, in-memory state) but carries coordinates. Trace it: sharer's phone -> location update every 5s -> location service stores current loc -> fan out via pub/sub to the 3 viewers watching -> their maps update; viewer closes the share -> unsubscribe -> no more fan-out to them. Throttled (adaptive) location ingest + current-location store + real-time pub/sub fan-out to subscribed viewers is the shape."),
      K("api", "API / flow",
        "share: device -> location update { lat, lng, ts } every ~Ns (throttled, adaptive)\nstore: location service -> SET current_location[sharer] (in-memory/Redis)\nsubscribe: viewer opens share -> subscribe to sharer's updates (WebSocket)\nfan-out: each update -> pub/sub -> gateways of subscribed viewers -> push coords -> map moves\nunsubscribe: viewer leaves -> stop fan-out to them\n(nearby): geo index for 'who/what is near me' queries"),
      K("data_model", "Data model",
        "current location (in-memory/Redis): sharer -> { lat, lng, ts } (latest only) ; optional TTL\nsubscriptions: viewer -> sharer(s) they're watching -> fan-out targets\nconnections: viewer -> gateway hosting their WebSocket (routing)\n(optional) trail/history: recent path (if showing movement) -> short-lived store\ngeo index: sharers by location (for nearby/discovery use cases)"),
      C("deep_dive", "Deep dive: ingesting & fanning out location updates",
        "The core is moving frequent location updates from one device to many viewers in real time. INGEST: the sharing device periodically reports its location; the key design choice is FREQUENCY — high-frequency continuous reporting gives a smooth live view but DRAINS the battery and uses bandwidth, so updates are THROTTLED (every few seconds) and ideally ADAPTIVE: report MORE often when the sharer is moving fast (a driving courier) or actively being watched, and LESS often (or pause) when stationary or when no one's watching — drastically cutting cost while keeping the view useful. Updates flow over a connection (a persistent WebSocket for low-latency bidirectional, or lightweight HTTP/MQTT) to a location service. CURRENT-LOCATION STORE: for live viewing, only the LATEST location per sharer matters, so store it in a fast IN-MEMORY store (Redis) keyed by sharer (overwrite each update) — small, fast, no need to persist every point for the live use case (history, if shown, is a separate short-lived store). FAN-OUT (the scaling part): each new location must reach all CURRENT VIEWERS of that sharer in real time — so, like presence/chat, the service PUBLISHES the update to a pub/sub layer that routes it to the gateway servers holding the subscribed viewers' connections, which push the coordinates to clients (the map dot moves). SUBSCRIPTION SCOPING is the key efficiency lever (same as presence): only fan out to viewers who are ACTIVELY watching this sharer right now (they subscribed on opening the share, unsubscribe on leaving) — never broadcast to everyone — so fan-out is bounded by active viewers. SMOOTHING: clients often INTERPOLATE between received points (animate the dot gliding) so a 5-second update interval still looks smooth. Throttled/adaptive ingest + a current-location in-memory store + real-time pub/sub fan-out scoped to active viewers (+ client interpolation) is the core interviewers probe (mirroring presence with coordinates)."),
      C("deep_dive", "Deep dive: scale, battery/bandwidth efficiency & geo",
        "Beyond the basic flow, the design must scale to many sharers/viewers while sparing devices, and support geo use cases. BATTERY/BANDWIDTH EFFICIENCY (device side): constant GPS + network is the enemy of phone battery, so the system minimizes device cost — THROTTLE update frequency, make it ADAPTIVE (movement-/visibility-based: fast when driving + watched, slow/paused when idle or unwatched — e.g. don't send updates if no one is viewing), batch/compress updates, and use efficient transports; significant-change/geofence triggers (report on meaningful movement rather than fixed intervals) further cut updates. This 'don't send what no one needs' principle (driven by whether there are active viewers and whether the location changed) is the main efficiency lever. FAN-OUT SCALE: with many sharers each having viewers, total real-time fan-out is large — shard sharers/connections across gateway servers, route updates via pub/sub to the gateways with subscribers, and (as in presence) only push to active viewers; a popular share (many viewers) is a larger fan-out (mitigated by the pub/sub layer + only-active-viewers). CONNECTION SCALE: millions of WebSocket connections (sharers + viewers) -> horizontally scaled stateful gateways (the chat/presence gateway pattern). CURRENT-STATE STORE scale -> in-memory, sharded by sharer, latest-only (cheap). GEO/NEARBY: for use cases like 'find friends near me' or matching nearby drivers (the Uber-location pattern), index sharers' locations in a GEOSPATIAL index (geohash/quadtree) updated as they move, enabling proximity queries — distinct from the point-to-point share fan-out. RELIABILITY/consistency: location is best-effort/eventually-consistent (a slightly stale dot is fine), so favor availability/efficiency; handle disconnects (stop sharing on prolonged silence, like presence timeout). So device-side throttling/adaptivity (battery) + scoped pub/sub fan-out + horizontally-scaled gateways + an optional geo index is how it scales efficiently — the operational substance interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "BATTERY/BANDWIDTH on the sharer's device is the headline constraint -> throttle + adaptive frequency (by movement + active viewers) + significant-change triggers + don't send when unwatched. FAN-OUT to viewers -> pub/sub scoped to active viewers only; popular shares (many viewers) are larger fan-outs. CONNECTION SCALE (sharers + viewers, real-time) -> horizontally scaled stateful gateways. UPDATE FREQUENCY vs SMOOTHNESS -> a few-second interval + client-side interpolation looks smooth without high-frequency uploads. REAL-TIME LATENCY -> push (WebSocket/pub-sub), not polling. CURRENT-STATE -> in-memory latest-only (history optional). Trade-offs: high-frequency updates (smooth, precise — battery/bandwidth/scale cost) vs throttled+adaptive+interpolated (efficient, slightly less precise — the right default); push/WebSocket (real-time, connection cost) vs polling (simple, laggy/inefficient); only-active-viewers fan-out (efficient — subscription tracking) vs broadcast (simple, wasteful); in-memory latest-only (fast, cheap, no history) vs persist-every-point (history/replay, costly — only if needed); adaptive frequency (battery-smart, more logic) vs fixed interval (simple, wasteful when idle). Closing signal: throttled, adaptive (movement-/viewer-aware) location ingest from devices, a fast in-memory current-location store, and real-time pub/sub fan-out scoped to active viewers (with client interpolation for smoothness), on horizontally-scaled gateways, plus a geo index for nearby use cases — real-time live location at scale that's easy on batteries (essentially presence with coordinates)."),
      C("deep_dive", "Deep dive: privacy, history, accuracy & operations",
        "Operationally live location is privacy-sensitive real-time infrastructure. Privacy & consent: location is highly sensitive, so sharing is explicit and scoped (who can see, for how long — temporary shares with expiry), revocable instantly (stop sharing -> stop fan-out + clear current location), and access-controlled on every viewer subscription; coarsen precision where appropriate; this is a first-class requirement, not an afterthought. Adaptive reporting policy: the device decides when/how often to report based on movement (accelerometer/significant-change), whether anyone is actively viewing (the server can signal 'viewers present/absent' to throttle up/down), and power state — minimizing battery while keeping the live view useful. History/trail: if showing a path or storing trips (e.g. a delivery route), persist recent points in a short-lived/time-series store (TTL'd) — but the live view needs only the latest. Accuracy & smoothing: GPS is noisy, so smooth/snap (map-matching to roads for vehicles) and interpolate between points for animation; handle inaccurate/jumpy readings. Connection management: persistent connections for sharers + viewers (gateways), with reconnect handling; stop sharing on prolonged disconnect (like presence timeout). Use-case variants: friend sharing (point-to-point fan-out), ride/delivery tracking (one courier watched by customer + dispatch, plus ETA computation via routing), and nearby discovery (geo index). Notifications: arrival/geofence alerts ('your friend arrived home'). Scale/sharding: sharers + connections sharded across gateways; current-location store sharded; geo index distributed. Reliability: best-effort (stale dot acceptable). Observability: update ingest rate, fan-out latency to viewers, active shares/viewers, battery-impacting update frequency, and connection counts are the SLOs. The spine holds: consented, throttled/adaptive ingest + in-memory current location + scoped real-time pub/sub fan-out + interpolation, on scaled gateways, with privacy controls, optional trail history, and geo for nearby."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you avoid draining the sharer's battery?' throttle updates (every few seconds, not continuous) and make frequency ADAPTIVE — faster when moving/actively watched, slower or paused when stationary or when no one is viewing; significant-change triggers; the server can tell the device whether viewers are present. 'Make a 5s interval look smooth?' client-side interpolation animates the dot between points. 'Deliver updates in real time?' push via WebSocket + pub/sub (not polling) to subscribed viewers. 'Fan-out to many viewers?' publish each update to the gateways holding ACTIVE viewers' connections; scope to active viewers only (subscribe on open, unsubscribe on leave). 'Where store location?' latest-only in a fast in-memory store (Redis) per sharer; history/trail in a short-lived store if needed. 'Scale connections?' horizontally scaled stateful gateways (presence/chat pattern). 'Nearby use cases?' a geospatial index (geohash/quadtree) for proximity queries. 'Privacy?' explicit, time-scoped, revocable sharing + access checks + precision control. 'Relation to presence?' same architecture (connections, subscriptions, pub/sub fan-out, in-memory state) but with coordinates instead of online/offline. Each returns to the spine: throttled/adaptive ingest + in-memory current location + scoped real-time pub/sub fan-out + interpolation, scaled gateways, privacy-controlled."),
    ],
    "Live location sharing tests throttled, ADAPTIVE (movement-/viewer-aware) location ingestion that spares device battery, a fast IN-MEMORY current-location store, and real-time pub/sub FAN-OUT scoped to active VIEWERS (WebSocket gateways + client interpolation for smoothness), scaled horizontally — essentially the PRESENCE design with coordinates, plus a geo index for nearby use cases and privacy controls. The signal is throttled/adaptive ingest + scoped real-time fan-out (battery + scale), not continuous high-frequency GPS broadcast to everyone.",
    [
      G("constant_gps", "Sending continuous high-frequency GPS updates from the device.", "Throttle + adapt frequency (by movement / active viewers) + significant-change triggers + interpolate client-side — protect battery/bandwidth.", "Streams location continuously / every second; drains battery, floods bandwidth."),
      G("broadcast_all", "Fanning out updates to everyone instead of active viewers.", "Scope fan-out to currently-subscribed/active viewers (subscribe on open, unsubscribe on leave) via pub/sub.", "Broadcasts location to all contacts regardless of who's watching; wasteful."),
      G("polling_or_db", "Viewers poll for location / storing every point in a durable DB for live view.", "Push updates in real time (WebSocket/pub-sub); store latest-only in-memory (history separately if needed).", "Clients poll for updates (laggy) or every location point is written to a relational DB."),
    ],
    0.5, DIAG.livelocation, "Live location sharing architecture"),

  // ─────────────────────────── CI/CD PIPELINE ──────────────────────────────
  TT("sysd_m10", "sysd_m10_t7", 7, "Design a CI/CD Pipeline", "design-cicd-pipeline",
    ["case-study", "ci-cd", "isolation", "automation"],
    "Every push to every repo should automatically build the code, run the tests, and (if green) deploy it — across thousands of repos and concurrent builds, running each project's untrusted build scripts safely, fast, and reliably. How do you build a CI/CD system?",
    "A push fires a WEBHOOK that triggers a PIPELINE (stages: build → test → deploy); a pool of build AGENTS/RUNNERS executes the stages in ISOLATED environments (containers — the build scripts are untrusted and need clean, reproducible envs), with dependency CACHING, ARTIFACTS stored in object storage, and a deploy stage using strategies (rolling/canary). Builds queue and agents autoscale. It's the code-judge sandbox + a workflow pipeline. Isolated pipeline execution + scalable reliable build/deploy are the substance.",
    [
      C("requirements", "Requirements",
        "Functional: on a code event (push/PR/merge), automatically run a PIPELINE — BUILD the code, run TESTS, and on success DEPLOY (CD) — defined per repo (stages, steps); provide logs, status, and artifacts; support many repos/teams. Non-functional: ISOLATION (each build runs arbitrary project-defined scripts — effectively untrusted code — that must be isolated for security + reproducibility), SCALE (many repos, many concurrent builds, spikes at peak hours), RELIABILITY (builds shouldn't flake due to infra; retry; consistent results), FAST FEEDBACK (developers wait on builds — speed matters via caching/parallelism), and reproducibility (clean, consistent build environments). Clarify scope: a CI/CD system (GitHub Actions / Jenkins / GitLab CI / CircleCI style). The defining challenges combine two earlier patterns: (1) running BUILD/TEST jobs that execute arbitrary, project-defined scripts in ISOLATED, clean environments — this is essentially the CODE-JUDGE sandbox problem (untrusted code, resource limits, fresh reproducible env per build), and (2) orchestrating a multi-STAGE PIPELINE (build -> test -> deploy) reliably with dependencies/retries — essentially the WORKFLOW-engine pattern — across a SCALABLE pool of build agents, with caching for speed and artifact storage. So the design centers on isolated pipeline execution (runners/containers) + scalable, reliable build/deploy orchestration (queue + agents + caching + artifacts + deploy strategies)."),
      K("estimation", "Capacity estimation (with numbers)",
        "Builds: many repos * frequent pushes -> thousands of concurrent builds at peak (spiky).\nEach build: pull code -> build -> test (-> deploy) in an ISOLATED env (container) -> minutes.\nIsolation: a fresh container/VM per build (untrusted scripts, clean reproducible env), torn down.\nScale: a queue + a pool of build AGENTS/runners ; autoscale with the queue (spiky load).\nSpeed: cache dependencies/build layers ; parallelize jobs/test shards.\nArtifacts: build outputs -> object storage.\nTakeaway: queue + isolated autoscaled runners executing pipeline stages, with caching for\nspeed + artifacts + reliable orchestration + deploy strategies."),
      C("hld", "High-level design",
        "TRIGGER: a code event (push/PR) fires a WEBHOOK from the version control system to the CI/CD service, which looks up the repo's PIPELINE definition (stages/steps, e.g. in a YAML config) and enqueues build JOBS. EXECUTION: a pool of build AGENTS/RUNNERS pulls jobs from the QUEUE; each runs the pipeline STAGES — checkout code, BUILD, TEST (and on success, DEPLOY) — inside an ISOLATED environment (a fresh CONTAINER/VM per build: clean, reproducible, resource-limited, isolated from other builds and the host, since build scripts are arbitrary/untrusted), capturing LOGS and STATUS, then tearing the environment down. SPEED: dependency/build CACHING (restore cached deps/layers so builds don't redo everything) and PARALLELISM (run independent jobs / test shards concurrently). ARTIFACTS: build outputs (binaries, images, reports) are stored in OBJECT STORAGE and passed between stages / published. DEPLOY (CD): on a successful build of the right branch, the deploy stage ships the artifact using a strategy (rolling, blue-green, or CANARY) with health checks + rollback. The pipeline orchestration (stage ordering, dependencies, retries, fan-out/fan-in of parallel jobs) is workflow-like. AUTOSCALING: the agent pool scales with the build queue (spiky load). Trace it: push -> webhook -> enqueue pipeline -> agent pulls job -> isolated container: checkout + build (cache) + test -> store artifacts -> (if green + main) deploy canary -> status/logs reported. Webhook-triggered pipeline + queue + isolated autoscaled runners (build/test) + caching + artifacts + deploy strategies is the shape."),
      K("api", "API / flow",
        "trigger: VCS push/PR -> webhook -> CI/CD service -> load pipeline def -> enqueue jobs\nrunner (per job): provision isolated container/VM -> checkout -> build (restore cache) -> test\n   -> store artifacts (object storage) -> report logs/status -> tear down\nstages: build -> test -> deploy (ordered/dependent; parallel jobs/test shards fan-out)\ndeploy (CD): rolling / blue-green / canary + health checks + rollback\nscale: queue + autoscaled agent pool ; retries on infra flakes (idempotent)"),
      K("data_model", "Data model",
        "pipelines: per-repo definition (stages, steps, triggers, deps)\njobs/builds: queued/running/done ; logs, status, duration, commit\nrunners/agents: pool of isolated executors (containers/VMs), capacity, autoscale\ncache: dependency/build caches keyed by lockfile/inputs (speed)\nartifacts: build outputs in object storage (passed between stages / published)\ndeployments: target env, strategy (canary/rolling), health, rollback state"),
      C("deep_dive", "Deep dive: pipeline execution & isolation",
        "The execution core is running build/test stages in ISOLATED, reproducible environments — the code-judge sandbox problem applied to builds. ISOLATION: a CI build runs arbitrary, project-AUTHORED scripts (build commands, tests, custom steps) — effectively UNTRUSTED code from the repo's perspective (a malicious or buggy build script could harm the host, other builds, or exfiltrate secrets) — so each build runs in an ISOLATED environment: a fresh CONTAINER (or VM for stronger isolation) with resource limits (CPU/memory/time), isolated filesystem/network, and no access to other builds or host secrets beyond what's injected — and it's EPHEMERAL (created per build, destroyed after) so builds don't pollute each other and start from a CLEAN, REPRODUCIBLE state (the same inputs -> the same result, not contaminated by a previous build's leftovers). This clean-environment-per-build is essential both for security (isolating untrusted scripts) and CORRECTNESS (reproducible builds — no 'works on the dirty agent' flakiness). PIPELINE STAGES & ORCHESTRATION: a pipeline is a sequence/graph of stages (build -> test -> deploy) with dependencies — orchestrated like a WORKFLOW (the workflow-engine pattern): run stages in order, fan out independent jobs in PARALLEL (e.g. test shards, multiple platforms) and fan back in, stop on failure, and report per-stage status — the orchestrator tracks pipeline state and dispatches ready jobs to runners. CACHING for speed: builds repeatedly fetch the same dependencies / recompile, so CACHE dependencies and build layers (keyed by lockfiles/inputs) and restore them into the build env, drastically cutting build time (fast feedback) — balanced against cache correctness (invalidate when inputs change). SECRETS: builds need credentials (to pull deps, deploy) injected securely (secret store) without leaking into logs/other builds. So ephemeral isolated containers per build (untrusted scripts, clean reproducible env, resource-limited) + workflow-style staged/parallel orchestration + dependency caching is the execution core interviewers probe (it's the code-judge sandbox + a build pipeline)."),
      C("deep_dive", "Deep dive: scale, reliability & deployment",
        "Around execution sit scaling, reliability, and the CD (deploy) half. SCALE via QUEUE + AGENT POOL: builds are bursty (everyone pushes during the workday, a big merge triggers many), so jobs go onto a QUEUE consumed by a pool of build AGENTS/runners — throughput scales by adding agents, and you AUTOSCALE the pool with queue depth (spin up runners under load, down when idle), so spikes are absorbed (queued) rather than dropped. RELIABILITY: builds shouldn't fail due to infra — RETRY transiently-failed jobs (a runner crash re-queues the build), make orchestration resilient (the workflow engine resumes/retries), and isolate failures (one bad build can't break others — ephemeral sandboxes); distinguish infra flakes (retry) from real test failures (report). PARALLELISM: split work (test sharding, matrix builds across versions/platforms) across agents to cut wall-clock time. ARTIFACTS: build outputs (binaries, container images, test reports) are stored in OBJECT STORAGE / a registry, passed between stages and to deploy, and retained for traceability. DEPLOYMENT (CD): on a green build of the deployable branch, the deploy stage releases the artifact using a controlled STRATEGY — ROLLING (replace instances gradually), BLUE-GREEN (switch traffic to a new fleet), or CANARY (release to a small % first, watch metrics, then ramp) — with HEALTH CHECKS and automatic ROLLBACK on failure (the safe-deploy pattern; ties to the deployment/feature-flag designs). Approvals/gates can guard production. OBSERVABILITY: developers need fast LOGS, status, and notifications (build passed/failed) for quick feedback. SECURITY at scale: isolation, secret management, and supply-chain integrity (verify dependencies/artifacts). So a queue + autoscaled isolated agents + retries/parallelism + artifact storage + safe deploy strategies (canary/rolling + rollback) is how CI/CD scales reliably and ships safely — the operational substance interviewers probe."),
      C("bottlenecks", "Bottlenecks & trade-offs",
        "BUILD SPIKES (workday pushes, big merges) -> queue absorbs them + autoscale agents. ISOLATION of untrusted build scripts -> ephemeral containers/VMs (resource-limited, clean) — security + reproducibility. SLOW BUILDS (developer wait) -> dependency/layer CACHING + PARALLELISM (test shards/matrix) ; cache correctness vs speed. RELIABILITY -> retry infra flakes (idempotent), isolate failures, resumable orchestration. SECRETS leakage -> secure injection, not in logs. ARTIFACT storage growth -> object storage + retention. DEPLOY risk -> canary/rolling + health checks + rollback. Trade-offs: containers (fast, lighter isolation) vs VMs (stronger isolation, slower/heavier) — pick by trust/needs; ephemeral clean env (reproducible, isolated — provisioning cost) vs reused agents (fast start, contamination/flakiness risk); aggressive caching (fast builds — staleness/invalidation bugs) vs clean rebuilds (correct, slow); autoscale agents (handle spikes, cost-efficient — provisioning latency) vs fixed pool (simple, queues under load); canary/blue-green (safe deploys, infra complexity) vs deploy-all-at-once (simple, risky); parallel test shards (fast feedback, orchestration cost) vs serial (simple, slow). Closing signal: webhook-triggered pipelines orchestrated workflow-style (staged, parallel, retried), executed by an autoscaled pool of EPHEMERAL ISOLATED runners (containers/VMs for untrusted build scripts + clean reproducible envs) with dependency caching for speed and artifacts in object storage, plus safe CD (canary/rolling + health checks + rollback) — scalable, reliable, fast, secure automated build-test-deploy (the code-judge sandbox meets a workflow pipeline)."),
      C("deep_dive", "Deep dive: caching, security, deploy strategies & operations",
        "Operationally CI/CD is developer-critical infrastructure blending sandboxing, orchestration, and deployment. Runner fleet & isolation models: managed ephemeral containers (fast, common), VMs/microVMs for stronger isolation or full-OS needs, and self-hosted runners for special hardware/network — each build gets a clean, resource-capped, isolated environment, torn down after; warm pools reduce provisioning latency. Caching strategy: dependency caches (package managers), build/layer caches (Docker layer cache, incremental compilation), and test result caching — keyed by content/lockfiles, restored per build, invalidated on input change; caching is the biggest build-speed lever (and a correctness hazard if mis-keyed). Secrets & supply chain: inject secrets securely (a secrets manager) scoped per pipeline, mask them in logs, and protect the supply chain — pin/verify dependencies, sign artifacts, provenance (SLSA) — since CI is a high-value attack target (it has deploy credentials). Pipeline definition: declarative config in the repo (YAML) describing stages, triggers, matrix, dependencies, and conditions — versioned with the code. Deploy strategies (CD): rolling, blue-green, canary (with automated metric analysis), feature-flag-gated releases, environment promotion (dev -> staging -> prod), manual approval gates for prod, and automatic rollback on health-check failure (ties to the deployment + feature-flag designs). Artifacts & registries: store/publish binaries and container images to artifact repositories/registries (the package-registry design), retained and versioned. Observability & feedback: real-time logs, status checks back to the PR (block merge on red), notifications, build analytics (flaky-test detection, duration trends). Scale & multi-tenancy: isolate teams/orgs, fair scheduling so one team can't starve others, and quotas. Reliability: retry infra flakes, resumable pipelines, and idempotent steps. Observability: queue wait time, build duration + success rate, runner utilization, cache hit rate, deploy success/rollback rate, and flaky-test rate are the SLOs. The spine holds: webhook -> workflow-orchestrated pipeline -> autoscaled ephemeral isolated runners (cached, secret-injected) -> artifacts -> safe CD (canary/rollback), with supply-chain security and multi-tenant fairness."),
      C("deep_dive", "Common follow-ups & how it evolves",
        "Expect: 'How do you run arbitrary build scripts safely?' each build in an EPHEMERAL ISOLATED environment (fresh container/VM, resource-limited, isolated fs/network, torn down after) — the code-judge sandbox idea — giving both security (untrusted scripts) and a clean reproducible env. 'Scale to many concurrent builds + spikes?' a queue + an AUTOSCALED pool of build agents (scale with queue depth); the queue absorbs bursts. 'Make builds fast?' dependency/build-layer CACHING (restore deps, incremental builds) + PARALLELISM (test sharding, matrix). 'Orchestrate stages?' workflow-style — ordered/dependent stages, parallel jobs fan-out/fan-in, stop-on-failure, retries (the workflow-engine pattern). 'Reliability / flaky infra?' retry transient failures (idempotent), isolate failures (ephemeral sandboxes), resumable orchestration. 'Artifacts?' store build outputs/images in object storage / a registry, pass between stages. 'Deploy safely (CD)?' canary/blue-green/rolling + health checks + automatic rollback + approval gates. 'Secrets?' inject from a secret store, scoped, masked in logs; secure the supply chain (CI has deploy creds). 'Pipeline config?' declarative YAML in the repo, versioned. Each returns to the spine: webhook -> workflow-orchestrated pipeline -> autoscaled ephemeral isolated runners (cached, secured) -> artifacts -> safe CD with rollback."),
    ],
    "A CI/CD pipeline tests two composed patterns: running untrusted project build scripts in EPHEMERAL ISOLATED runners (containers/VMs — clean, reproducible, resource-limited; the code-judge sandbox) and WORKFLOW-style orchestration of staged, parallel, retried build→test→deploy across an autoscaled agent pool fed by a queue, with dependency CACHING for speed, ARTIFACTS in object storage, and safe CD strategies (canary/rolling + health checks + rollback). The signal is isolated reproducible execution + scalable reliable pipeline orchestration + safe deploy, not 'run the build on a shared server'.",
    [
      G("no_isolation", "Running builds on shared/persistent agents without isolation.", "Run each build in an ephemeral isolated environment (container/VM, resource-limited, clean) — untrusted scripts + reproducibility demand it.", "Builds run on a shared long-lived agent; contamination, flakiness, and security exposure."),
      G("no_queue_autoscale", "A fixed set of runners with no queue/autoscaling for spiky load.", "Queue jobs + autoscale the agent pool with demand so build spikes are absorbed (queued), not dropped.", "Builds fail/stall under peak load; no queue, no elastic agents."),
      G("unsafe_deploy", "Deploying all at once with no strategy/rollback after a green build.", "Use canary/blue-green/rolling + health checks + automatic rollback (and approval gates) for safe CD.", "CD ships to all of prod at once; no canary/health-check/rollback."),
    ],
    0.6, DIAG.cicd, "CI/CD pipeline architecture"),
];

// ── 3 exercises per topic ────────────────────────────────────────────────────
const xpFor = (l) => (l === "warmup" ? 5 : l === "easy" ? 10 : l === "medium" ? 15 : 20);
const diffFor = (l) => (l === "warmup" ? 0.1 : l === "easy" ? 0.2 : l === "medium" ? 0.4 : 0.6);
function pm(moduleId, o) {
  return { trackKey: TRACK_KEY, moduleId, topicId: o.topicId, exerciseId: o.exerciseId,
    position: o.position, level: o.level, type: "pattern_match", title: o.title, scenario: o.scenario,
    instructions: "Pick the best answer.", starterCode: "", expectedSolution: o.correct,
    blanks: [{ options: o.options }], testCases: [{ type: "pattern_match", correct: o.correct, explanation: o.explanation }],
    hints: [], xpReward: xpFor(o.level), difficulty: diffFor(o.level) };
}

